var mqttClient = null;
var running = false;
var timer = null;
var count = 0;
var dataPoints = [];
var MAX_POINTS = 100;
var orgShort = '';
var mqttToken = '';

// Setup chart
var canvas = document.createElement('canvas');
document.getElementById('chartArea').appendChild(canvas);
requestAnimationFrame(drawChart);

// Fetch MQTT connection info from API
fetch('/api/channels', {credentials: 'include'}).then(function(r) { return r.json(); }).then(function(data) {
  orgShort = data.connection.org_short;
  var info = document.getElementById('mqttInfo');
  if (data.tokens && data.tokens.length > 0) {
    info.innerHTML = '<b>MQTT:</b> ws://' + window.location.host + '/ws/mqtt | <b>Topic prefix:</b> org/' + orgShort + '/ | <b>Token:</b> Use channel token from Channels page';
  } else {
    info.innerHTML = '<b>No device token found.</b> Create one in the Channels page first.';
  }
}).catch(function() {
  document.getElementById('mqttInfo').textContent = 'Failed to load MQTT info';
});

function connectMQTT() {
  if (mqttClient && mqttClient.connected) return Promise.resolve();
  return new Promise(function(resolve, reject) {
    // Connect via WebSocket to MQTT broker
    var loc = window.parent ? window.parent.location : window.location;
    var wsUrl = (loc.protocol === 'https:' ? 'wss://' : 'ws://') + loc.host + '/ws/mqtt';
    // Fetch a fresh token
    fetch('/api/channels', {credentials: 'include'}).then(function(r) { return r.json(); }).then(function(data) {
      orgShort = data.connection.org_short;
      // Use the CueStack session cookie for auth via the backend publish endpoint
      // For real MQTT: would use channel token as username/password
      mqttClient = mqtt.connect(wsUrl, {
        clientId: 'simulator-' + Math.random().toString(36).substr(2, 8),
        clean: true,
        connectTimeout: 5000,
      });
      mqttClient.on('connect', function() {
        updateStatus('Connected', '#f0fde8', '#15803d');
        addLog('MQTT connected to ' + wsUrl);
        resolve();
      });
      mqttClient.on('error', function(err) {
        updateStatus('Error', '#fef2f2', '#dc2626');
        addLog('MQTT error: ' + err.message);
        reject(err);
      });
      mqttClient.on('close', function() {
        updateStatus('Disconnected', '#fef2f2', '#dc2626');
      });
    });
  });
}

function toggleSimulation() {
  running = !running;
  var btn = document.getElementById('toggleBtn');
  if (running) {
    btn.textContent = 'Stop Simulation'; btn.className = 'running';
    connectMQTT().then(function() {
      startSending();
    }).catch(function(err) {
      addLog('Failed to connect: ' + err.message);
      running = false;
      btn.textContent = 'Start Simulation'; btn.className = '';
    });
  } else {
    btn.textContent = 'Start Simulation'; btn.className = '';
    clearInterval(timer);
    if (mqttClient) { mqttClient.end(); mqttClient = null; }
    updateStatus('Disconnected', '#fef2f2', '#dc2626');
  }
}

function startSending() {
  clearInterval(timer);
  timer = setInterval(sendSample, parseInt(document.getElementById('rate').value));
}

function sendSample() {
  if (!mqttClient || !mqttClient.connected) return;
  var channel = document.getElementById('channel').value;
  var meanT = parseFloat(document.getElementById('meanTemp').value);
  var meanH = parseFloat(document.getElementById('meanHumid').value);
  var noise = parseFloat(document.getElementById('noise').value);
  var freq = parseFloat(document.getElementById('freq').value);
  var t = count * (parseInt(document.getElementById('rate').value) / 1000);
  var temp = meanT + noise * (Math.random() - 0.5) * 2 + Math.sin(2 * Math.PI * freq * t);
  var humid = meanH + noise * (Math.random() - 0.5) * 2 + Math.cos(2 * Math.PI * freq * t) * 0.5;
  var payload = { temperature: +temp.toFixed(2), humidity: +humid.toFixed(2), t: t };
  var topic = 'org/' + orgShort + '/' + channel;
  mqttClient.publish(topic, JSON.stringify(payload));
  dataPoints.push(payload);
  if (dataPoints.length > MAX_POINTS) dataPoints.shift();
  document.getElementById('liveTemp').textContent = payload.temperature.toFixed(1) + '°C';
  document.getElementById('liveHumid').textContent = payload.humidity.toFixed(1) + '%';
  count++;
  document.getElementById('counter').textContent = count + ' samples sent';
  addLog('[' + new Date().toLocaleTimeString() + '] ' + topic + ': T=' + payload.temperature + '°C H=' + payload.humidity + '%');
}

function updateStatus(text, bg, color) {
  var s = document.getElementById('status');
  s.textContent = text; s.style.background = bg; s.style.color = color;
}

function addLog(msg) {
  var log = document.getElementById('log');
  log.innerHTML = '<div>' + msg + '</div>' + log.innerHTML;
  if (log.children.length > 50) log.lastChild.remove();
}

function drawChart() {
  var w = canvas.parentElement.clientWidth;
  var h = canvas.parentElement.clientHeight;
  canvas.width = w; canvas.height = h;
  var ctx = canvas.getContext('2d');
  ctx.fillStyle = '#1e1e1e'; ctx.fillRect(0, 0, w, h);
  if (dataPoints.length < 2) { requestAnimationFrame(drawChart); return; }
  var temps = dataPoints.map(function(d) { return d.temperature; });
  var minT = Math.min.apply(null, temps) - 1;
  var maxT = Math.max.apply(null, temps) + 1;
  ctx.strokeStyle = '#ef4444'; ctx.lineWidth = 2; ctx.beginPath();
  dataPoints.forEach(function(d, i) {
    var x = (i / (MAX_POINTS - 1)) * w;
    var y = h - ((d.temperature - minT) / (maxT - minT)) * h;
    i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
  }); ctx.stroke();
  var humids = dataPoints.map(function(d) { return d.humidity; });
  var minH = Math.min.apply(null, humids) - 1;
  var maxH = Math.max.apply(null, humids) + 1;
  ctx.strokeStyle = '#3b82f6'; ctx.beginPath();
  dataPoints.forEach(function(d, i) {
    var x = (i / (MAX_POINTS - 1)) * w;
    var y = h - ((d.humidity - minH) / (maxH - minH)) * h;
    i === 0 ? ctx.moveTo(x, y) : ctx.lineTo(x, y);
  }); ctx.stroke();
  ctx.fillStyle = '#ef4444'; ctx.font = '11px monospace';
  ctx.fillText('Temp: ' + temps[temps.length-1].toFixed(1) + '°C', 8, 14);
  ctx.fillStyle = '#3b82f6';
  ctx.fillText('Humid: ' + humids[humids.length-1].toFixed(1) + '%', 8, 28);
  requestAnimationFrame(drawChart);
}

['meanTemp','meanHumid','noise','freq'].forEach(function(id) {
  var el = document.getElementById(id);
  var val = document.getElementById(id + 'Val');
  el.oninput = function() {
    var suffix = id === 'meanTemp' ? '°C' : id === 'meanHumid' ? '%' : id === 'freq' ? ' Hz' : '';
    val.textContent = el.value + suffix;
  };
});
